//api.github.com/repos/UsagiApp/Usagi/releases/assets/389508392","id":389508392,"node_id":"RA_kwDORshtus4XN20o","name":"release.apk","label":null,"uploader":{"login":"dragonx943","id":131387159,"node_id":"U_kgDOB9TPFw","avatar_url":"https://avatars.githubusercontent.com/u/131387159?v=4","gravatar_id":"","url":"https://api.github.com/users/dragonx943","html_url":"https://github.com/dragonx943","followers_url":"https://api.github.com/users/dragonx943/followers","following_url":"https://api.github.com/users/dragonx943/following{/other_user}","gists_url":"https://api.github.com/users/dragonx943/gists{/gist_id}","starred_url":"https://api.github.com/users/dragonx943/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/dragonx943/subscriptions","organizations_url":"https://api.github.com/users/dragonx943/orgs","repos_url":"https://api.github.com/users/dragonx943/repos","events_url":"https://api.github.com/users/dragonx943/events{/privacy}","received_events_url":"https://api.github.com/users/dragonx943/received_events","type":"User","user_view_type":"public","site_admin":false},"content_type":"application/vnd.android.package-archive","state":"uploaded","size":15036811,"digest":"sha256:a7b446c01a481f533f627ef0341b8b98466c0d02c266a4bf03dfbfbe05930396","download_count":2395,"created_at":"2026-04-05T19:50:31Z","updated_at":"2026-04-05T20:01:47Z","browser_download_url":"https://github.com/UsagiApp/Usagi/releases/download/v0.0.1/release.apk"}],"tarball_url":"https://api.github.com/repos/UsagiApp/Usagi/tarball/v0.0.1","zipball_url":"https://api.github.com/repos/UsagiApp/Usagi/zipball/v0.0.1","body":"# Usagi [0.0.1](https://github.com/UsagiApp/Usagi/releases/tag/v0.0.1)\\r\\n\\r\\n**This is the first stable version of Usagi, a manga reader app for Android. It's not just a fork, it's much more than that.**\\r\\n\\r\\n## What's different\\r\\n\\r\\n**Unlike Kotatsu, Usagi pursues a completely different ideal.**\\r\\n\\r\\nWe offer the highest level of app customization with many features never before seen in Kotatsu or any other fork. The app itself doesn't come with any pre-loaded content; users are free to find, select, and install any content according to their own reading preferences, instead of relying on pre-provided content as before.\\r\\n\\r\\n**Freedom to explore. Freedom to search. Freedom to customize. Freedom of preference. Freedom to read.**\\r\\n\\r\\n## What's changed\\r\\n\\r\\n- Content must be loaded from external plugins\\r\\n- Enhanced the ability to read data from external and backward compatibility\\r\\n- Increased compatibility with other Kotatsu forks\\r\\n- Removed welcome screen (no more pre-loaded content)\\r\\n- Provided several fixes / patches for crash bugs, and memory leaks\\r\\n- Updated some translations from Weblate\\r\\n\\r\\n**Thank you everyone for following and using Usagi. Thank you for your support and contributions.**","reactions":{"url":"https://api.github.com/repos/UsagiApp/Usagi/releases/305467377/reactions","total_count":7,"+1":1,"-1":0,"laugh":0,"hooray":0,"confused":0,"heart":4,"rocket":1,"eyes":1}},"beta":{"url":"https://api.github.com/repos/UsagiApp/Usagi/releases/315010990","assets_url":"https://api.github.com/repos/UsagiApp/Usagi/releases/315010990/assets","upload_url":"https://uploads.github.com/repos/UsagiApp/Usagi/releases/315010990/assets{?name,label}","html_url":"https://github.com/UsagiApp/Usagi/releases/tag/v0.0.2-b3","id":315010990,"author":{"login":"dragonx943","id":131387159,"node_id":"U_kgDOB9TPFw","avatar_url":"https://avatars.githubusercontent.com/u/131387159?v=4","gravatar_id":"","url":"https://api.github.com/users/dragonx943","html_url":"https://github.com/dragonx943","followers_url":"https://api.github.com/users/dragonx943/followers","following_url":"https://api.github.com/users/dragonx943/following{/other_user}","gists_url":"https://api.github.com/users/dragonx943/gists{/gist_id}","starred_url":"https://api.github.com/users/dragonx943/starred{/owner}{/rep